import urllib.request
import urllib.error
import json
import ssl
import hmac
import hashlib
from typing import Optional, Dict, Any

def fetch_url_content(url: str, method: str = 'GET', headers: Optional[Dict[str, str]] = None, 
                      data: Optional[bytes] = None, timeout: int = 30) -> Dict[str, Any]:
    if headers is None:
        headers = {}
    
    req = urllib.request.Request(url, data=data, headers=headers, method=method)
    
    try:
        with urllib.request.urlopen(req, timeout=timeout) as response:
            content = response.read()
            return {
                'status_code': response.status,
                'headers': dict(response.headers),
                'content': content.decode('utf-8'),
                'url': response.url
            }
    except urllib.error.HTTPError as e:
        return {
            'status_code': e.code,
            'headers': dict(e.headers),
            'content': e.read().decode('utf-8'),
            'error': str(e)
        }
    except urllib.error.URLError as e:
        return {
            'status_code': None,
            'headers': {},
            'content': '',
            'error': str(e)
        }
    except Exception as e:
        return {
            'status_code': None,
            'headers': {},
            'content': '',
            'error': str(e)
        }


def process_webhook(event: Dict[str, Any], context: Any = None) -> Dict[str, Any]:
    body = event.get('body', '')
    headers = event.get('headers', {})
    query_params = event.get('queryStringParameters', {}) or {}
    path = event.get('path', '')
    http_method = event.get('httpMethod', 'POST')
    
    if isinstance(body, str):
        try:
            payload = json.loads(body) if body else {}
        except json.JSONDecodeError:
            payload = {'raw': body}
    else:
        payload = body
    
    webhook_data = {
        'headers': headers,
        'payload': payload,
        'query_params': query_params,
        'path': path,
        'method': http_method,
        'source_ip': headers.get('X-Forwarded-For', '').split(',')[0].strip() if headers.get('X-Forwarded-For') else None
    }
    
    return webhook_data


def verify_webhook_signature(payload: str, signature: str, secret: str, 
                             algorithm: str = 'sha256', header_prefix: str = 'sha256=') -> bool:
    if algorithm == 'sha256':
        expected_signature = hmac.new(
            secret.encode('utf-8'),
            payload.encode('utf-8'),
            hashlib.sha256
        ).hexdigest()
    elif algorithm == 'sha1':
        expected_signature = hmac.new(
            secret.encode('utf-8'),
            payload.encode('utf-8'),
            hashlib.sha1
        ).hexdigest()
    else:
        return False
    
    if header_prefix:
        signature = signature.replace(header_prefix, '')
    
    return hmac.compare_digest(expected_signature, signature)


def route_webhook(webhook_data: Dict[str, Any], integrations_config: Dict[str, Any]) -> Dict[str, Any]:
    path = webhook_data.get('path', '')
    headers = webhook_data.get('headers', {})
    
    integration_type = None
    for key in ['github', 'stripe', 'slack', 'shopify', 'twilio', 'sendgrid']:
        if key in path.lower():
            integration_type = key
            break
    
    if not integration_type:
        user_agent = headers.get('User-Agent', '').lower()
        for key in ['github', 'stripe', 'slack', 'shopify', 'twilio', 'sendgrid']:
            if key in user_agent:
                integration_type = key
                break
    
    if integration_type and integration_type in integrations_config:
        config = integrations_config[integration_type]
        if config.get('verify_signature'):
            signature_header = config.get('signature_header', 'X-Hub-Signature-256')
            signature = headers.get(signature_header, '')
            secret = config.get('webhook_secret', '')
            algorithm = config.get('signature_algorithm', 'sha256')
            prefix = config.get('signature_prefix', 'sha256=')
            
            if signature and secret:
                is_valid = verify_webhook_signature(
                    json.dumps(webhook_data.get('payload', {})),
                    signature,
                    secret,
                    algorithm,
                    prefix
                )
                webhook_data['signature_valid'] = is_valid
    
    webhook_data['integration_type'] = integration_type
    return webhook_data


def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    integrations_config = {
        'github': {
            'verify_signature': True,
            'signature_header': 'X-Hub-Signature-256',
            'signature_algorithm': 'sha256',
            'signature_prefix': 'sha256=',
            'webhook_secret': ''
        },
        'stripe': {
            'verify_signature': True,
            'signature_header': 'Stripe-Signature',
            'signature_algorithm': 'sha256',
            'signature_prefix': 't=',
            'webhook_secret': ''
        },
        'slack': {
            'verify_signature': True,
            'signature_header': 'X-Slack-Signature',
            'signature_algorithm': 'sha256',
            'signature_prefix': 'v0=',
            'webhook_secret': ''
        },
        'shopify': {
            'verify_signature': True,
            'signature_header': 'X-Shopify-Hmac-SHA256',
            'signature_algorithm': 'sha256',
            'signature_prefix': '',
            'webhook_secret': ''
        }
    }
    
    webhook_data = process_webhook(event, context)
    webhook_data = route_webhook(webhook_data, integrations_config)
    
    return {
        'statusCode': 200,
        'headers': {
            'Content-Type': 'application/json'
        },
        'body': json.dumps({
            'message': 'Webhook processed successfully',
            'integration_type': webhook_data.get('integration_type'),
            'signature_valid': webhook_data.get('signature_valid')
        })
    }


def display_content(content_data: Dict[str, Any]) -> None:
    print(f"Status Code: {content_data.get('status_code')}")
    print(f"URL: {content_data.get('url')}")
    print("\nHeaders:")
    for key, value in content_data.get('headers', {}).items():
        print(f"  {key}: {value}")
    print("\nContent:")
    print(content_data.get('content'))
    if 'error' in content_data:
        print(f"\nError: {content_data.get('error')}")